/*  on.standard.system.boardtype.inqBoardCdCount  */
 SELECT CASE WHEN COUNT(*) = 0 THEN 'notDupl' ELSE 'dupl' END AS isBoardTypeDupl
   FROM STB_SM_BOARDTYPE_MNG
  WHERE BOARD_CD = #{boardCd}

/*  on.standard.system.boardtype.mergeInsBoardType  */
INSERT INTO STB_SM_BOARDTYPE_MNG (
           BOARD_CD
         , USE_YN
         , BOARD_KOR_NM
         , BOARD_ENG_NM
         , BOARD_COMMENT
         , NTI_YN
         , RCMD_YN
         , TITLE_YN
         , CONTENT_YN
         , CONTENT_EDITOR_YN
         , ATTCH_FILE_YN
         , FILE_LIMIT_CNT
         , FILE_LIMIT_MB
         , SECRET_YN
         , REPLY_YN
         , TEMPCOL_1, TEMPCOL_2, TEMPCOL_3
         , TEMPCOL_4, TEMPCOL_5, TEMPCOL_6
         , REG_USER
         , REG_DATE
) VALUES (
           #{boardCd}
         , #{useYn}
         , #{boardKorNm}
         , #{boardEngNm}
         , #{boardComment}
         , #{ntiYn}
         , #{rcmdYn}
         , #{titleYn}
         , #{contentYn}
         , #{contentEditorYn}
         , #{attchFileYn}
         , #{fileLimitCnt}
         , #{fileLimitMb}
         , #{secretYn}
         , #{replyYn}
         , #{tempCol1}, #{tempCol2}, #{tempCol3}
         , #{tempCol4}, #{tempCol5}, #{tempCol6}
         , #{loginUserId}
         , NOW() /* 최초 등록일 */
 )
 ON DUPLICATE KEY UPDATE
       USE_YN            = #{useYn}
     , BOARD_KOR_NM      = #{boardKorNm}
     , BOARD_ENG_NM      = #{boardEngNm}
     , BOARD_COMMENT     = #{boardComment}
     , NTI_YN            = #{ntiYn}
     , RCMD_YN           = #{rcmdYn}
     , TITLE_YN          = #{titleYn}
     , CONTENT_YN        = #{contentYn}
     , CONTENT_EDITOR_YN = #{contentEditorYn}
     , ATTCH_FILE_YN     = #{attchFileYn}
     , FILE_LIMIT_CNT    = #{fileLimitCnt}
     , FILE_LIMIT_MB     = #{fileLimitMb}
     , SECRET_YN         = #{secretYn}
     , REPLY_YN          = #{replyYn}
     , TEMPCOL_1         = #{tempCol1}
     , TEMPCOL_2         = #{tempCol2}
     , TEMPCOL_3         = #{tempCol3}
     , TEMPCOL_4         = #{tempCol4}
     , TEMPCOL_5         = #{tempCol5}
     , TEMPCOL_6         = #{tempCol6}
     , UPD_USER          = #{loginUserId}
     , UPD_DATE          = NOW()
